package com.example.api.service;

import com.example.api.model.Product;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import jakarta.annotation.PostConstruct;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class ProductService {

    private static final Logger logger = LoggerFactory.getLogger(ProductService.class);

    private final Map<Long, Product> productStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(1);

    @PostConstruct
    public void init() {
        logger.info("Initializing ProductService with sample data");
        createProduct(new Product(null, "Laptop", "High-performance laptop", 1299.99));
        createProduct(new Product(null, "Smartphone", "Latest smartphone model", 899.99));
        createProduct(new Product(null, "Headphones", "Noise-cancelling headphones", 349.99));
        logger.info("ProductService initialized with {} sample products", productStore.size());
    }

    public List<Product> getAllProducts() {
        logger.info("Retrieving all products from store");
        List<Product> products = new ArrayList<>(productStore.values());
        logger.info("Successfully retrieved {} products", products.size());
        return products;
    }

    public Optional<Product> getProductById(Long id) {
        logger.info("Retrieving product with id={}", id);
        Optional<Product> product = Optional.ofNullable(productStore.get(id));
        if (product.isPresent()) {
            logger.info("Successfully retrieved product: {}", product.get());
        } else {
            logger.warn("Product with id={} not found", id);
        }
        return product;
    }

    public Product createProduct(Product product) {
        Long id = idGenerator.getAndIncrement();
        product.setId(id);
        productStore.put(id, product);
        logger.info("Successfully created product: {}", product);
        return product;
    }

    public Optional<Product> updateProduct(Long id, Product updatedProduct) {
        logger.info("Updating product with id={}", id);
        if (!productStore.containsKey(id)) {
            logger.warn("Cannot update - product with id={} not found", id);
            return Optional.empty();
        }
        updatedProduct.setId(id);
        productStore.put(id, updatedProduct);
        logger.info("Successfully updated product: {}", updatedProduct);
        return Optional.of(updatedProduct);
    }

    public boolean deleteProduct(Long id) {
        logger.info("Deleting product with id={}", id);
        Product removed = productStore.remove(id);
        if (removed != null) {
            logger.info("Successfully deleted product: {}", removed);
            return true;
        } else {
            logger.warn("Cannot delete - product with id={} not found", id);
            return false;
        }
    }

    public List<Product> searchProducts(String keyword) {
        logger.info("Searching products with keyword='{}'", keyword);
        List<Product> results = productStore.values().stream()
                .filter(p -> p.getName().toLowerCase().contains(keyword.toLowerCase())
                        || p.getDescription().toLowerCase().contains(keyword.toLowerCase()))
                .toList();
        logger.info("Search for '{}' returned {} results", keyword, results.size());
        return results;
    }
}

