package com.example.api.controller;

import com.example.api.model.Product;
import com.example.api.service.ProductService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private static final Logger logger = LoggerFactory.getLogger(ProductController.class);

    private final ProductService productService;

    public ProductController(ProductService productService) {
        this.productService = productService;
        logger.info("ProductController initialized");
    }

    @GetMapping
    public ResponseEntity<List<Product>> getAllProducts() {
        logger.info("GET /api/products - Fetching all products");
        List<Product> products = productService.getAllProducts();
        logger.info("GET /api/products - Returning {} products", products.size());
        return ResponseEntity.ok(products);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Object> getProductById(@PathVariable Long id) {
        logger.info("GET /api/products/{} - Fetching product by id", id);
        return productService.getProductById(id)
                .<ResponseEntity<Object>>map(product -> {
                    logger.info("GET /api/products/{} - Product found", id);
                    return ResponseEntity.ok(product);
                })
                .orElseGet(() -> {
                    logger.warn("GET /api/products/{} - Product not found", id);
                    return ResponseEntity.status(HttpStatus.NOT_FOUND)
                            .body(Map.of("error", "Product not found", "id", id));
                });
    }

    @PostMapping
    public ResponseEntity<Product> createProduct(@RequestBody Product product) {
        logger.info("POST /api/products - Creating new product with name='{}'", product.getName());
        Product created = productService.createProduct(product);
        logger.info("POST /api/products - Product created with id={}", created.getId());
        return ResponseEntity.status(HttpStatus.CREATED).body(created);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Object> updateProduct(@PathVariable Long id, @RequestBody Product product) {
        logger.info("PUT /api/products/{} - Updating product", id);
        return productService.updateProduct(id, product)
                .<ResponseEntity<Object>>map(updated -> {
                    logger.info("PUT /api/products/{} - Product updated successfully", id);
                    return ResponseEntity.ok(updated);
                })
                .orElseGet(() -> {
                    logger.warn("PUT /api/products/{} - Product not found for update", id);
                    return ResponseEntity.status(HttpStatus.NOT_FOUND)
                            .body(Map.of("error", "Product not found", "id", id));
                });
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Object> deleteProduct(@PathVariable Long id) {
        logger.info("DELETE /api/products/{} - Deleting product", id);
        if (productService.deleteProduct(id)) {
            logger.info("DELETE /api/products/{} - Product deleted successfully", id);
            return ResponseEntity.ok(Map.of("message", "Product deleted successfully", "id", id));
        } else {
            logger.warn("DELETE /api/products/{} - Product not found for deletion", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(Map.of("error", "Product not found", "id", id));
        }
    }

    @GetMapping("/search")
    public ResponseEntity<List<Product>> searchProducts(@RequestParam String keyword) {
        logger.info("GET /api/products/search?keyword='{}' - Searching products", keyword);
        List<Product> results = productService.searchProducts(keyword);
        logger.info("GET /api/products/search - Found {} results for keyword='{}'", results.size(), keyword);
        return ResponseEntity.ok(results);
    }
}

// === config/RequestLoggingFilter.java ===
package com.example.api.config;

import jakarta.servlet.*;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
@Order(1)
public class RequestLoggingFilter implements Filter {

    private static final Logger logger = LoggerFactory.getLogger(RequestLoggingFilter.class);

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain)
            throws IOException, ServletException {
        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        long startTime = System.currentTimeMillis();
        String method = httpRequest.getMethod();
        String uri = httpRequest.getRequestURI();
        String queryString = httpRequest.getQueryString();
        String fullPath = queryString != null ? uri + "?" + queryString : uri;

        logger.info("Incoming request: {} {} from {}", method, fullPath, httpRequest.getRemoteAddr());

        try {
            chain.doFilter(request, response);
        } finally {
            long duration = System.currentTimeMillis() - startTime;
            int status = httpResponse.getStatus();
            logger.info("Completed request: {} {} - Status: {} - Duration: {}ms", method, fullPath, status, duration);
        }
    }
}

